  "cdk_nag_finding": {
    "rule_id": "AwsSolutions-ECS2",
    "resource_id": "ASHCDKNagScanner/tavus-pipecat-example--infra--template.yaml/TaskDefinition",
    "compliance": "Non-Compliant",
    "exception_reason": "N/A",
    "rule_level": "Error",
    "rule_info": "The ECS Task Definition includes a container definition that directly specifies environment variables."
  },
  "cfn_resource": {
    "Resources": {
      "TaskDefinition": {
        "Type": "AWS::ECS::TaskDefinition",
        "Properties": {
          "Family": {
            "Fn::Sub": "${EnvironmentName}-task"
          },
          "Cpu": {
            "Ref": "TaskCpu"
          },
          "Memory": {
            "Ref": "TaskMemory"
          },
          "NetworkMode": "awsvpc",
          "RequiresCompatibilities": [
            "FARGATE"
          ],
          "ExecutionRoleArn": {
            "Fn::GetAtt": [
              "TaskExecutionRole",
              "Arn"
            ]
          },
          "TaskRoleArn": {
            "Fn::GetAtt": [
              "TaskRole",
              "Arn"
            ]
          },
          "ContainerDefinitions": [
            {
              "Name": "pipecat-bot",
              "Image": {
                "Fn::Sub": "${AWS::AccountId}.dkr.ecr.${AWS::Region}.amazonaws.com/${ECRRepository}:latest"
              },
              "PortMappings": [
                {
                  "ContainerPort": {
                    "Ref": "ContainerPort"
                  },
                  "Protocol": "tcp"
                }
              ],
              "LogConfiguration": {
                "LogDriver": "awslogs",
                "Options": {
                  "awslogs-group": {
                    "Ref": "LogGroup"
                  },
                  "awslogs-region": {
                    "Ref": "AWS::Region"
                  },
                  "awslogs-stream-prefix": "pipecat"
                }
              },
              "Secrets": [
                {
                  "Name": "DEEPGRAM_API_KEY",
                  "ValueFrom": {
                    "Fn::Sub": "arn:aws:ssm:${AWS::Region}:${AWS::AccountId}:parameter/${EnvironmentName}/DEEPGRAM_API_KEY"
                  }
                },
                {
                  "Name": "CARTESIA_API_KEY",
                  "ValueFrom": {
                    "Fn::Sub": "arn:aws:ssm:${AWS::Region}:${AWS::AccountId}:parameter/${EnvironmentName}/CARTESIA_API_KEY"
                  }
                },
                {
                  "Name": "TAVUS_API_KEY",
                  "ValueFrom": {
                    "Fn::Sub": "arn:aws:ssm:${AWS::Region}:${AWS::AccountId}:parameter/${EnvironmentName}/TAVUS_API_KEY"
                  }
                },
                {
                  "Name": "TAVUS_REPLICA_ID",
                  "ValueFrom": {
